          width: 6vw;
          height: 6vw;
      }
      .key.large {
          width: 12vw;
      }
      .key.space {
          min-width: 50vw;
      }
  }
</style>
</head>
<body>

<div class="output" contenteditable id="output"></div>

<div class="keyboard-container" id="keyboard"></div>

<script>
  const keyboardLayout = [
      ['`','1','2','3','4','5','6','7','8','9','0','-','=','Backspace'],
      ['Tab','q','w','e','r','t','y','u','i','o','p','[',']','\\'],
      ['CapsLock','a','s','d','f','g','h','j','k','l',';','\'','Enter'],
      ['Shift','z','x','c','v','b','n','m',',','.','/','Shift'],
      [' ',' ']
  ];

  const keyboardContainer = document.getElementById('keyboard');
  const outputElement = document.getElementById('output');

  function appendCharacter(character) {
      switch (character) {
          case 'Backspace':
              outputElement.textContent = outputElement.textContent.slice(0, -1);
              break;
          case 'Tab':
              outputElement.textContent += "\t";
              break;
          case 'Enter':
              outputElement.textContent += "\n";
              break;
          case 'CapsLock':
          case 'Shift':
              // Currently no functionality for CapsLock or Shift in this simple example
              break;
          case ' ':
              outputElement.textContent += ' ';
              break;
          default:
              outputElement.textContent += character;
      }
  }

  function createKeyElement(key) {
      const keyElement = document.createElement('div');
      keyElement.className = 'key';
      if (key.length === 1) { // Single character key
          keyElement.textContent = key;
      } else { // Special keys
          keyElement.textContent = key;
          keyElement.classList.add('large');
          if (key === ' ') {
              keyElement.classList.add('space');
          }
      }

      keyElement.addEventListener('click', () => appendCharacter(key));
      return keyElement;
  }

  keyboardLayout.forEach(row => {
      const rowElement = document.createElement('div');
      rowElement.className = 'keyboard-row';
      row.forEach(key => {
          rowElement.appendChild(createKeyElement(key));
      });
      keyboardContainer.appendChild(rowElement);
  });

  // To keep focus on contenteditable and avoid losing keystrokes
  outputElement.addEventListener('blur', () => {
      setTimeout(() => outputElement.focus());
  });

  // Focus on output to start typing
  outputElement.focus();
</script>

</body>
</html>
```

In this example, I've laid out a keyboard using CSS, arranged in rows for visual clarity. When a key is clicked, it triggers the `appendCharacter` function, which detects if it's a character key or a control key (like Backspace or Enter) and updates the text displayed in a `contenteditable` div (`<div class="output" contenteditable id="output"></div>`). The `contenteditable` attribute makes it possible for users to type directly into the div, just like an input field.

Please note that a `contenteditable` div is used rather than a `textarea` or `input` to properly handle the `Tab` key in this simple example. Keep in mind that this is a basic implementation and lacks more sophisticated features like handling the CapsLock or Shift key to toggle letter case, managing cursor position, or implementing additional input logic. For a fully functional virtual keyboard, you'll need a more complex script and possibly additional libraries to manage these aspects correctly.

